    private string newEventTitle = "";
    private DateTime newEventDate = DateTime.Today;
    private TimeSpan newEventStartTime = new(9, 0, 0);
    private TimeSpan newEventEndTime = new(10, 0, 0);
    private HashSet<string> newEventAttendees = new();

    protected override async Task OnInitializedAsync()
    {
        teamMembers = await CalendarService.GetTeamMembersAsync();
        selectedMembers = new HashSet<string>(teamMembers);
        await LoadMonth();
    }

    private async Task LoadMonth()
    {
        events = await CalendarService.GetEventsAsync(currentDate.Year, currentDate.Month);
        BuildCalendarDays();
    }

