.calendar-container {
    padding: 1rem;
    max-width: 1200px;
    margin: 0 auto;
}

.month-nav {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1rem;
}

.month-label {
    margin: 0;
    flex: 1;
    text-align: center;
}

.team-filter {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
}

.filter-checkbox {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.calendar-main {
    display: flex;
    gap: 1.5rem;
}

.calendar-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 1px;
    background: #dee2e6;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    overflow: hidden;
    flex: 1;
}

.day-header {
    background: #e9ecef;
    padding: 0.5rem;
    text-align: center;
    font-weight: 600;
    font-size: 0.85rem;
}

.day-cell {
    background: #fff;
    padding: 0.5rem;
    min-height: 80px;
    cursor: pointer;
    transition: background-color 0.15s;
    position: relative;
}

.day-cell:hover {
    background: #f0f4ff;
}

.day-cell.today {
    background: #e7f1ff;
    border: 2px solid #0d6efd;
}

.day-cell.outside-month {
    background: #f8f9fa;
    color: #adb5bd;
}

.day-cell.selected {
    background: #cfe2ff;
}

.day-number {
    font-weight: 500;
    font-size: 0.9rem;
}

.event-dots {
