    height: 8px;
    border-radius: 50%;
    background: #0d6efd;
}

.dot:nth-child(2) {
    background: #198754;
}

.dot:nth-child(3) {
    background: #ffc107;
}

.more-label {
    font-size: 0.7rem;
    color: #6c757d;
}

