.month-nav {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1rem;
}

.month-label {
    margin: 0;
    flex: 1;
    text-align: center;
}

.team-filter {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
}

.filter-checkbox {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.calendar-main {
    display: flex;
    gap: 1.5rem;
}

.calendar-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 1px;
    background: #dee2e6;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    overflow: hidden;
    flex: 1;
}

.day-header {
    background: #e9ecef;
    padding: 0.5rem;
    text-align: center;
    font-weight: 600;
    font-size: 0.85rem;
}

.day-cell {
    background: #fff;
    padding: 0.5rem;
    min-height: 80px;
    cursor: pointer;
    transition: background-color 0.15s;
    position: relative;
}

.day-cell:hover {
    background: #f0f4ff;
}

.day-cell.today {
    background: #e7f1ff;
    border: 2px solid #0d6efd;
}

.day-cell.outside-month {
    background: #f8f9fa;
    color: #adb5bd;
}

.day-cell.selected {
    background: #cfe2ff;
}

.day-number {
    font-weight: 500;
    font-size: 0.9rem;
}

.event-dots {
    display: flex;
    flex-wrap: wrap;
    gap: 3px;
    margin-top: 0.25rem;
    align-items: center;
}

.dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #0d6efd;
}

.dot:nth-child(2) {
    background: #198754;
}

.dot:nth-child(3) {
    background: #ffc107;
}

.more-label {
    font-size: 0.7rem;
    color: #6c757d;
}

/* Day Detail Side Panel */
.day-panel {
    width: 320px;
    min-width: 320px;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 1rem;
    background: #fff;
    max-height: 600px;
    overflow-y: auto;
}

.day-panel h4 {
    margin-bottom: 1rem;
    font-size: 1.1rem;
}

.no-events {
    color: #6c757d;
    font-style: italic;
}

.event-list {
    list-style: none;
    padding: 0;
    margin: 0 0 1rem;
}

.event-item {
    border: 1px solid #e9ecef;
    border-radius: 0.375rem;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
}

.event-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.event-time {
    font-size: 0.85rem;
    color: #495057;
}

.event-attendees {
    font-size: 0.8rem;
    color: #6c757d;
    margin-bottom: 0.5rem;
}

.new-event-btn {
    width: 100%;
}

/* New Event Form */
.new-event-form .form-group {
    margin-bottom: 0.75rem;
}

.new-event-form .form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.25rem;
    font-size: 0.9rem;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 1rem;
}

